local TpPenGroup = Tabs.Teleports:AddLeftGroupbox("Chuồng ")
TpPenGroup:AddButton({
    Text="→ Chuồng của tôi ",
    Func=function()
        local root = game.Players.LocalPlayer.Character and game.Players.LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
        if not root then return end
        local pen = M.findMyPen()
        if pen then
            local pos = M.getPenBasePosition()
            if pos then root.CFrame=CFrame.new(pos) end
            Library:Notify({Title="Đã dịch chuyển ",Description="Chuồng #"..pen.Name.." ",Time=2})
        else
            Library:Notify({Title="Lỗi ",Description="Không tìm thấy bút!",Time=2})
        end
    end,
})
TpPenGroup:AddButton({
    Text="→ Thú cưng đầu tiên",
    Func=function()
        local root = game.Players.LocalPlayer.Character and game.Players.LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
        if not root then return end
        local pets = M.getMyPenPets()
        if #pets==0 then Library:Notify({Title="Chuồng ",Description="Không có thú cưng trong chuồng. ",Time=2}) return end
        local part = pets[1]:FindFirstChildWhichIsA("BasePart")
        if part then
            root.CFrame=CFrame.new(part.Position+Vector3.new(0,3,0))
            local info = {name=pets[1]:GetAttribute("Name") or pets[1].Name}
            Library:Notify({Title="Đã dịch chuyển ",Description=info.name.." ",Time=2})
        end
    end,
})

